```
curl -H'content-type:application/json' 'http://localhost:9220/_msearch?error_trace=true&pretty' -d '
{"index":["companiestable"],"ignore_unavailable":true,"preference":1572975891903}
{"aggs":{"topicFilters":{"filters":{"filters":[{"span_near":{"clauses":[{"span_term":{"description":"compani"}},{"span_term":{"description":"technolog"}}],"slop":2,"in_order":false}},{"span_near":{"clauses":[{"span_term":{"description":"market"}},{"span_term":{"description":"technolog"}}],"slop":2,"in_order":false}}]},"aggs":{"sampler":{"sampler":{"shard_size":1000},"aggs":{"subtopics":{"terms":{"field":"description","size":48,"include":["market","technolog", "compani"]}}}}}}},"size":0,"_source":{"excludes":[]},"query":{"bool":{"must":[{"match_phrase":{"description":"Real Estate"}},{"wildcard":{"description":"*"}}]}}}
